solutions.python:
class Solution:
  def solve(self, branch_name: str) -> bool:
    # Use a regular expression to match invalid characters and Unicode sequences
    import re
    if re.search(r'[^a-zA-Z0-9-/]', branch_name):
      return False
    return True
